import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, deadlines):
    min_total_time = float('inf')
    best_node = None

    for i, customer_pos in enumerate(unvisited_customers):
        for truck_pos in all_truck_pos:
            distance_to_customer = np.linalg.norm(truck_pos - customer_pos)
            arrival_time = current_time + distance_to_customer / truck_speed

            if deadlines[i] != None and arrival_time > deadlines[i]:
                penalty = (arrival_time - deadlines[i]) * 2
            else:
                penalty = 0

            total_time = arrival_time + penalty

            if total_time < min_total_time:
                min_total_time = total_time
                best_node = i

    return best_node
